export interface DurationObservation { duration: number; recordedAt: number }

export function smoothDuration(observations: DurationObservation[], strategy: 'latest' | 'average' | 'p95' | 'median'): number {
  if (!observations.length) { return 0 }
  if (strategy === 'latest') { return observations.reduce((latest, value) => value.recordedAt > latest.recordedAt ? value : latest).duration }
  const values = observations.map(value => value.duration).sort((a, b) => a - b)
  if (strategy === 'average') { return Math.round(values.reduce((sum, value) => sum + value, 0) / values.length) }
  if (strategy === 'p95') { return values[Math.ceil(0.95 * values.length) - 1] }

